                  </div>
                  <div>
                    <Icon
                      icon={item.styling}
                      width="40"
                      height="40"
                      className="font-semibold text-primary mt-2"
                    />
                  </div>
                </div>
              </div>
            ))}
          </Slider>
        </div>
      </div>
    </section>
  );
};

